import logging
from logging.handlers import TimedRotatingFileHandler
import os

# Create a logger
logger = logging.getLogger('application')
logger.setLevel(logging.INFO)

# Configure file handler to write logs to /var/log/application/
if not os.path.exists('/var/log/application/'):
    os.makedirs('/var/log/application/')
file_handler = TimedRotatingFileHandler('/var/log/application/application.log', when='midnight', interval=1, backupCount=30)
file_handler.setLevel(logging.INFO)

# Configure formatter
formatter = logging.Formatter('%(asctime)s - %(name)s - %(levelname)s - %(message)s')
file_handler.setFormatter(formatter)

# Add file handler to logger
logger.addHandler(file_handler)

# Example usage:
logger.info('This is an info message.')
logger.warning('This is a warning message.')
logger.error('This is an error message.')